
import gmpy2
from Cryptodome.Util.number import *
import primefac
def broadcast_attack(data):
    def extended_gcd(a,b):
        x,y=0,1
        lastx,lasty=1,0
        while b:
            a,(q,b)=b,divmod(a,b)
            x,lastx=lastx-q*x,x
            y,lasty=lasty-q*y,y
        return(lastx,lasty,a)
    def chenese_remainder_theorem(items):
        N=1
        for a,n in items:
            N*=n
            result=0
        for a,n in items:
            m=N//n
            r,s,d=extended_gcd(n,m)
            if d != 1:
                N=N/n
                continue
            result +=a*s*m
        return result % N,N
    x,n =chenese_remainder_theorem(data)
    m=gmpy2.iroot(x,3)[0]
    return m

